-- Aetherion: PNGs definitivos integrados aos itens
-- Rode depois do supabase_schema.sql e seed_data.sql

alter table public.items add column if not exists icon_url text;
alter table public.items add column if not exists visual_key text;

on conflict (key) do update set name=excluded.name, type=excluded.type, rarity=excluded.rarity, icon_url=excluded.icon_url, visual_key=excluded.visual_key, stackable=excluded.stackable;
